def egcd(a, b):
    if a == 0:
        return (b, 0, 1)
    else:
        g, x, y = egcd(b % a, a)
        return (g, y - (b // a) * x, x)

def mod_inverse(a, m):
    if m <= 1:
        raise ValueError("Modulo must be greater than 1")
    g, x, _ = egcd(a, m)
    if g != 1:
        raise ValueError(f"Modular inverse of {a} (mod {m}) does not exist. GCD({a}, {m}) = {g}")
    return x % m

def chinese_remainder_theorem(n, a):
    if len(n) != len(a):
        raise ValueError("Lists of moduli and remainders must have the same length")

    N = 1
    for ni in n:
        if ni <= 1:
            raise ValueError("All moduli must be greater than 1")
        N *= ni

    x_sum = 0
    for i in range(len(n)):
        ni = n[i]
        ai = a[i]

        Ni = N // ni

        yi = mod_inverse(Ni, ni)

        x_sum += ai * Ni * yi

    return x_sum % N
